/* ─────────────────────────────────────────────────────────────
   Progress Bar
───────────────────────────────────────────────────────────── */
function ProgressBar({ currentStep }) {
  return (
    <div className={s.progressWrap}>
      {STEP_LABELS.map((label, i) => {
        const stepNum = i + 1;
        const done    = stepNum < currentStep;
        const active  = stepNum === currentStep;
        return (
          <div key={stepNum} className={s.progressItem}>
            <div
              className={s.progressCircle}
              style={{
                background: done ? C.green : active ? C.layla : 'transparent',
                border: `2px solid ${done ? C.green : active ? C.layla : C.border}`,
                color: done || active ? '#fff' : C.textSecondary,
              }}
            >
              {done ? '✓' : stepNum}
            </div>
            <div
              className={s.progressLabel}
              style={{ color: active ? C.text : done ? C.green : C.textSecondary }}
            >
              {label}
            </div>
            {i < TOTAL_STEPS - 1 && (
              <div
                className={s.progressLine}
                style={{ background: done ? C.green : C.border }}
              />
            )}
          </div>
        );
      })}
    </div>
  );
}

