/* ─────────────────────────────────────────────────────────────
   Step 3 — IBKR Account Setup
───────────────────────────────────────────────────────────── */
function StepIBKR({ state, dispatch }) {
  const { ibkr } = state;
  const [testing, setTesting]   = useState(false);
  const [testMsg, setTestMsg]   = useState('');
  const [testOk,  setTestOk]    = useState(null);
  const [idError, setIdError]   = useState('');

  const set = (key, value) =>
    dispatch({ type: 'SET_IBKR', payload: { ...ibkr, [key]: value, connectionTested: false } });

  const validateId = (val) => {
    if (!val) return '';
    if (!/^U\d{7,8}$/.test(val)) return 'Account ID must be U followed by 7–8 digits (e.g. U1234567)';
    return '';
  };

  const handleIdChange = (val) => {
    setIdError(validateId(val));
    set('accountId', val.toUpperCase());
  };

  const testConnection = async () => {
    setTesting(true);
    setTestMsg('');
    setTestOk(null);
    try {
      const res = await api(
        `/api/bot-instances/test-connection?account_id=${encodeURIComponent(ibkr.accountId)}&port=${ibkr.gatewayPort}`
      );
      if (res?.connected) {
        setTestOk(true);
        setTestMsg('Connection successful — IB Gateway is reachable.');
        dispatch({ type: 'SET_IBKR', payload: { ...ibkr, connectionTested: true } });
      } else {
        setTestOk(false);
        setTestMsg(res?.error || 'Could not connect. Check that IB Gateway is running on the specified port.');
      }
    } catch {
      setTestOk(false);
      setTestMsg('Connection test available after activation.');
    }
    setTesting(false);
  };

  const instructions = [
    {
      num:   1,
      title: 'Download IB Gateway',
      body:  'Install IB Gateway from Interactive Brokers. This lightweight app runs in the background and provides API access to your account — it does not require the full TWS platform.',
    },
    {
      num:   2,
      title: 'Enable API Access',
      body:  'In IB Gateway: Configure → Settings → API → Enable ActiveX and Socket Clients. Set port to 4002 (or your choice). Check "Allow connections from localhost only" for security.',
    },
    {
      num:   3,
      title: 'Note Your Account ID',
      body:  'Your IBKR account ID starts with U followed by 7–8 digits (e.g., U1234567). You can find it in the Account section of Client Portal.',
    },
  ];

  return (
    <div className={s.stepBody}>
      <div className={s.stepHeaderRow}>
        <div className={s.stepIconWrap} style={{ background: `${C.blue}18`, border: `1px solid ${C.blue}33` }}>
          <span className={s.stepIconEmoji}>🔗</span>
        </div>
        <div>
          <h2 className={s.stepTitle}>Connect Your IBKR Account</h2>
          <p className={s.stepDesc}>Follow these steps to set up IB Gateway, then enter your account details below.</p>
        </div>
      </div>

      <div className={s.instructionList}>
        {instructions.map(ins => (
          <div key={ins.num} className={s.instructionRow}>
            <div className={s.instructionNum} style={{ background: `${C.blue}20`, border: `1px solid ${C.blue}40`, color: C.blue }}>
              {ins.num}
            </div>
            <div className={s.instructionContent}>
              <div className={s.instructionTitle}>{ins.title}</div>
              <div className={s.instructionBody}>{ins.body}</div>
            </div>
          </div>
        ))}
      </div>

      <div className={s.infoNote} style={{ borderColor: `${C.blue}33`, background: `${C.blue}0D` }}>
        <span style={{ color: C.blue, fontWeight: 600 }}>Security note:</span>{' '}
        Your password is never stored. You authenticate directly through IB Gateway using your IBKR credentials.
      </div>

      <div className={s.twoColRow} style={{ marginTop: 20 }}>
        <div className={s.fieldGroup} style={{ flex: 2 }}>
          <label className={s.fieldLabel}>IBKR Account ID</label>
          <input
            className={s.textInput}
            style={{ borderColor: idError ? C.red : ibkr.accountId && !idError ? C.green : undefined }}
            value={ibkr.accountId}
            onChange={e => handleIdChange(e.target.value)}
            placeholder="U1234567"
            maxLength={9}
            spellCheck={false}
          />
          {idError && <div className={s.fieldError}>{idError}</div>}
          {!idError && ibkr.accountId && <div className={s.fieldOk}>Format looks correct</div>}
        </div>

        <div className={s.fieldGroup} style={{ flex: 1 }}>
          <label className={s.fieldLabel}>Gateway Port</label>
          <input
            className={s.textInput}
            type="number"
            min={4001}
            max={4099}
            value={ibkr.gatewayPort}
            onChange={e => set('gatewayPort', parseInt(e.target.value, 10) || 4002)}
          />
        </div>
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginTop: 8 }}>
        <button
          className={s.testConnBtn}
          onClick={testConnection}
          disabled={testing || !ibkr.accountId || !!idError}
          style={{
            borderColor: testing ? C.border : C.blue,
            color:       testing ? C.textSecondary : C.blue,
            cursor:      testing || !ibkr.accountId || !!idError ? 'not-allowed' : 'pointer',
            opacity:     !ibkr.accountId || !!idError ? 0.5 : 1,
          }}
        >
          {testing ? 'Testing...' : 'Test Connection'}
        </button>
        {testMsg && (
          <span
            className={s.testMsg}
            style={{ color: testOk === true ? C.green : testOk === false ? C.red : C.textSecondary }}
          >
            {testOk === true ? '✓' : testOk === false ? '✗' : 'ℹ'} {testMsg}
          </span>
        )}
      </div>
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────
   Step 4 — Client ID
───────────────────────────────────────────────────────────── */
function StepClientId({ state, dispatch }) {
  const { clientId } = state;
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    (async () => {
      setLoading(true);
      try {
        const res = await api('/api/wizard/available-client-ids');
        if (res?.available) {
          dispatch({ type: 'SET_CLIENT_ID', payload: { ...clientId, available: res.available } });
        }
      } catch {
        // Fall through — use fallback range
      }
      setLoading(false);
    })();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const takenIds   = TAKEN_CLIENT_IDS.map(t => t.id);
  const allIds     = Array.from({ length: 84 }, (_, i) => i + 16); // 16–99
  const available  = clientId.available.length > 0 ? clientId.available : allIds;
  const displayIds = Array.from({ length: 84 }, (_, i) => i + 16);

  const takenMap = {};
  TAKEN_CLIENT_IDS.forEach(t => { takenMap[t.id] = t.name; });

  return (
    <div className={s.stepBody}>
      <div className={s.stepHeaderRow}>
        <div className={s.stepIconWrap} style={{ background: `${C.purple}18`, border: `1px solid ${C.purple}33` }}>
          <span className={s.stepIconEmoji}>🔢</span>
        </div>
        <div>
          <h2 className={s.stepTitle}>Choose Your Client ID</h2>
          <p className={s.stepDesc}>Each bot needs a unique Client ID to connect to IB Gateway — think of it like a phone extension. IDs 13, 14, and 15 are already in use.</p>
        </div>
      </div>

      {loading ? (
        <div className={s.loadingRow}>
          <span style={{ color: C.textSecondary }}>Loading available IDs...</span>
        </div>
      ) : (
        <div className={s.clientIdGrid}>
          {displayIds.map(id => {
            const isTaken    = takenIds.includes(id);
            const isSelected = clientId.chosen === id;
            const isAvail    = available.includes(id);
            return (
              <button
                key={id}
                disabled={isTaken}
                onClick={() => dispatch({ type: 'SET_CLIENT_ID', payload: { ...clientId, chosen: id } })}
                className={s.clientIdCard}
                style={{
                  background:  isTaken ? `${C.border}20` : isSelected ? `${C.layla}20` : C.surface2,
                  border:      `2px solid ${isTaken ? C.border : isSelected ? C.layla : C.border}`,
                  opacity:     isTaken ? 0.45 : 1,
                  cursor:      isTaken ? 'not-allowed' : 'pointer',
                }}
              >
                <div
                  className={s.clientIdNumber}
                  style={{ color: isTaken ? C.textSecondary : isSelected ? C.layla : C.text }}
                >
                  {id}
                </div>
                {isTaken && (
                  <div className={s.clientIdBadge} style={{ color: C.red, background: `${C.red}18` }}>
                    {takenMap[id] || 'IN USE'}
                  </div>
                )}
                {isSelected && !isTaken && (
                  <div className={s.clientIdBadge} style={{ color: C.layla, background: `${C.layla}18` }}>
                    SELECTED
                  </div>
                )}
              </button>
            );
          })}
        </div>
      )}

      {clientId.chosen && (
        <div className={s.infoNote} style={{ marginTop: 16, borderColor: `${C.layla}33`, background: `${C.layla}0D` }}>
          <span style={{ color: C.layla, fontWeight: 600 }}>Client ID {clientId.chosen} selected.</span>{' '}
          Your bot will use this ID to connect to your IB Gateway instance.
        </div>
      )}
    </div>
  );
}

