/* ─────────────────────────────────────────────────────────────
   Step 6 — Signal Subscription
───────────────────────────────────────────────────────────── */
function StepSignals({ state, dispatch }) {
  const { signals } = state;
  const [allStrategies, setAllStrategies] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    (async () => {
      setLoading(true);
      try {
        const res = await api('/api/wizard/strategies');
        if (res?.strategies) setAllStrategies(res.strategies);
        else if (Array.isArray(res)) setAllStrategies(res);
      } catch {
        // Fallback: empty, user still can't advance without at least 1
      }
      setLoading(false);
    })();
  }, []);

  const longs  = allStrategies.filter(s => (s.direction || '').toUpperCase() !== 'SHORT');
  const shorts = allStrategies.filter(s => (s.direction || '').toUpperCase() === 'SHORT');

  const toggle = (name) => {
    const next = signals.subscribed.includes(name)
      ? signals.subscribed.filter(s => s !== name)
      : [...signals.subscribed, name];
    dispatch({ type: 'SET_SIGNALS', payload: { subscribed: next } });
  };

  const selectAll = (group) => {
    const names   = group.map(s => s.name || s);
    const current = new Set(signals.subscribed);
    const allOn   = names.every(n => current.has(n));
    let   next;
    if (allOn) {
      next = signals.subscribed.filter(n => !names.includes(n));
    } else {
      next = [...new Set([...signals.subscribed, ...names])];
    }
    dispatch({ type: 'SET_SIGNALS', payload: { subscribed: next } });
  };

  const StratCard = ({ strat, dirColor }) => {
    const name     = strat.name || strat;
    const selected = signals.subscribed.includes(name);
    return (
      <button
        className={s.signalCard}
        onClick={() => toggle(name)}
        style={{
          background:  selected ? `${dirColor}12` : C.surface2,
          border:      `1px solid ${selected ? dirColor : C.border}`,
          borderLeft:  `3px solid ${selected ? dirColor : 'transparent'}`,
        }}
      >
        <div
          className={s.signalCheck}
          style={{
            background: selected ? dirColor : 'transparent',
            border:     `2px solid ${selected ? dirColor : C.border}`,
          }}
        >
          {selected && '✓'}
        </div>
        <div className={s.signalInfo}>
          <div className={s.signalName}>{name}</div>
          {strat.win_rate != null && (
            <div className={s.signalMeta}>
              WR: {(strat.win_rate * 100).toFixed(0)}%
              {strat.sharpe != null && ` · Sharpe: ${strat.sharpe.toFixed(2)}`}
            </div>
          )}
        </div>
        {strat.recommended && (
          <span className={s.recommendedBadge} style={{ color: C.amber, background: `${C.amber}18` }}>★</span>
        )}
      </button>
    );
  };

  return (
    <div className={s.stepBody}>
      <div className={s.stepHeaderRow}>
        <div className={s.stepIconWrap} style={{ background: `${C.green}18`, border: `1px solid ${C.green}33` }}>
          <span className={s.stepIconEmoji}>📡</span>
        </div>
        <div>
          <h2 className={s.stepTitle}>Choose Your Signals</h2>
          <p className={s.stepDesc}>
            Your bot will only act on signals for strategies you've subscribed to.{' '}
            <span style={{ color: C.textSecondary }}>You can change this anytime.</span>
          </p>
        </div>
      </div>

      <div className={s.signalCountRow}>
        <span
          className={s.signalCount}
          style={{ color: signals.subscribed.length > 0 ? C.layla : C.textSecondary }}
        >
          {signals.subscribed.length} signal{signals.subscribed.length !== 1 ? 's' : ''} selected
        </span>
      </div>

      {loading ? (
        <div className={s.loadingRow}>
          <span style={{ color: C.textSecondary }}>Loading strategies...</span>
        </div>
      ) : (
        <div className={s.signalColumns}>
          {/* LONG column */}
          <div className={s.signalColumn}>
            <div className={s.signalColHeader} style={{ borderColor: `${C.green}40`, color: C.green }}>
              <span>LONG SIGNALS</span>
              <button
                className={s.selectAllBtn}
                style={{ color: C.green }}
                onClick={() => selectAll(longs)}
              >
                {longs.every(s => signals.subscribed.includes(s.name || s)) ? 'Deselect All' : 'Select All'}
              </button>
            </div>
            <div className={s.signalList}>
              {longs.length === 0 && (
                <div className={s.signalEmpty}>No long strategies loaded.</div>
              )}
              {longs.map(st => (
                <StratCard key={st.name || st} strat={st} dirColor={C.green} />
              ))}
            </div>
          </div>

          {/* SHORT column */}
          <div className={s.signalColumn}>
            <div className={s.signalColHeader} style={{ borderColor: `${C.red}40`, color: C.red }}>
              <span>SHORT SIGNALS</span>
              <button
                className={s.selectAllBtn}
                style={{ color: C.red }}
                onClick={() => selectAll(shorts)}
              >
                {shorts.every(s => signals.subscribed.includes(s.name || s)) ? 'Deselect All' : 'Select All'}
              </button>
            </div>
            <div className={s.signalList}>
              {shorts.length === 0 && (
                <div className={s.signalEmpty}>No short strategies loaded.</div>
              )}
              {shorts.map(st => (
                <StratCard key={st.name || st} strat={st} dirColor={C.red} />
              ))}
            </div>
          </div>
        </div>
      )}

      <div className={s.infoNote} style={{ marginTop: 16, borderColor: `${C.blue}33`, background: `${C.blue}0D` }}>
        <span style={{ color: C.blue, fontWeight: 600 }}>Tip:</span>{' '}
        Select at least 1 strategy to continue. Your bot works best with a diverse mix of long and short signals.
      </div>
    </div>
  );
}

